import React, {
  createContext,
  useContext,
  useState,
  useEffect,
  useCallback,
  useMemo
} from 'react';
import { Connection, clusterApiUrl, Keypair, PublicKey } from '@solana/web3.js';
import localforage from 'localforage';

const AppContext = createContext();

localforage.config({
  name: 'nexus-app',
  storeName: 'wallet-storage'
});

export function AppProvider({ children }) {

  /* ---------------- CORE NETWORK ---------------- */

  const [network, setNetwork] = useState('devnet');

  const connection = useMemo(() => {
    return new Connection(clusterApiUrl(network), 'confirmed');
  }, [network]);


  /* ---------------- WALLET STATE ---------------- */

  const [wallets, setWallets] = useState([]);
  const [activeWallet, setActiveWallet] = useState(null);
  const [balances, setBalances] = useState({});


  /* ---------------- DEPLOY + TRADING SETTINGS ---------------- */

  const [deployedToken, setDeployedToken] = useState(null);
  const [heliusEnabled, setHeliusEnabled] = useState(false);
  const [priorityFee, setPriorityFee] = useState(0);
  const [marketMakerEnabled, setMarketMakerEnabled] = useState(false);


  /* ---------------- UI + LOGS ---------------- */

  const [logs, setLogs] = useState([]);
  const [isLoading, setIsLoading] = useState(true);


  /* ---------------- LOAD STORED DATA ---------------- */

  useEffect(() => {
    const load = async () => {
      try {
        const savedWallets = await localforage.getItem('wallets');

        if (savedWallets) {
          const rebuilt = savedWallets.map(w => ({
            name: w.name,
            publicKey: w.publicKey,
            keypair: Keypair.fromSecretKey(Uint8Array.from(w.secretKey))
          }));

          setWallets(rebuilt);
          if (rebuilt.length > 0) setActiveWallet(rebuilt[0]);
        }

        const savedSettings = await localforage.getItem('settings');
        if (savedSettings) {
          setHeliusEnabled(savedSettings.heliusEnabled || false);
          setPriorityFee(savedSettings.priorityFee || 0);
        }

        const savedToken = await localforage.getItem('deployedToken');
        if (savedToken) setDeployedToken(savedToken);

      } catch (err) {
        console.error('Load error:', err);
      } finally {
        setIsLoading(false);
      }
    };

    load();
  }, []);


  /* ---------------- AUTO SAVE ---------------- */

  useEffect(() => {
    if (isLoading) return;

    const safeWallets = wallets.map(w => ({
      name: w.name,
      publicKey: w.publicKey,
      secretKey: Array.from(w.keypair.secretKey)
    }));

    localforage.setItem('wallets', safeWallets);
  }, [wallets, isLoading]);

  useEffect(() => {
    if (isLoading) return;

    localforage.setItem('settings', {
      heliusEnabled,
      priorityFee
    });
  }, [heliusEnabled, priorityFee, isLoading]);

  useEffect(() => {
    if (isLoading) return;

    if (deployedToken)
      localforage.setItem('deployedToken', deployedToken);
  }, [deployedToken, isLoading]);


  /* ---------------- BALANCE REFRESH ---------------- */

  const refreshBalances = useCallback(async () => {
    if (!connection || wallets.length === 0) return;

    const newBalances = {};

    for (const w of wallets) {
      try {
        const lamports = await connection.getBalance(
          new PublicKey(w.publicKey)
        );
        newBalances[w.publicKey] = lamports / 1_000_000_000;
      } catch {
        newBalances[w.publicKey] = 0;
      }
    }

    setBalances(newBalances);
  }, [connection, wallets]);

  useEffect(() => {
    if (wallets.length > 0) refreshBalances();
  }, [wallets, refreshBalances]);


  /* ---------------- WALLET ACTIONS ---------------- */

  const addWallet = useCallback((name) => {
    const kp = Keypair.generate();
    const wallet = {
      name: name || `Wallet ${wallets.length + 1}`,
      publicKey: kp.publicKey.toString(),
      keypair: kp
    };

    setWallets(prev => [...prev, wallet]);
    setActiveWallet(wallet);
    return wallet;
  }, [wallets.length]);

  const removeWallet = useCallback((publicKey) => {
    setWallets(prev => prev.filter(w => w.publicKey !== publicKey));
    setBalances(prev => {
      const copy = { ...prev };
      delete copy[publicKey];
      return copy;
    });
  }, []);


  /* ---------------- LOGGING ---------------- */

  const addLog = useCallback((msg, type = 'info') => {
    setLogs(prev => [
      ...prev,
      { msg, type, time: new Date().toLocaleTimeString() }
    ]);
  }, []);


  if (isLoading) return <div>Loading...</div>;


  return (
    <AppContext.Provider value={{
      network,
      setNetwork,
      connection,

      wallets,
      activeWallet,
      setActiveWallet,
      balances,
      refreshBalances,

      addWallet,
      removeWallet,

      deployedToken,
      setDeployedToken,

      heliusEnabled,
      setHeliusEnabled,
      priorityFee,
      setPriorityFee,

      marketMakerEnabled,
      setMarketMakerEnabled,

      logs,
      addLog
    }}>
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error('useApp must be used within AppProvider');
  }
  return context;
}
